//verifica id da sessao.
verificaidsessao.Call(&DevRandon, &IsAcessoConcedido, &IsAtualizaTudo, &wwpContext)

if &IsAcessoConcedido = true //Acesso concedido
	//Configuracao

	//RETORNA CONFIGURACOES DO APP VENDAS EXTERNAS FORCA DE VENDAS.
	For each order EmpCod, AppCod
		Where EmpCod = &wwpContext.EmpCod
		Where AppCod = TipoAplicativo.FORCAVENDAS

		//JDF ESSAS 3 CONFG NAO USA MAIS, O CADASTRO DO CLIENTE É ONLINE.
		//ObrigatorioEndereco
		&sdtConfiguracoes.IsObrEndCli = false //iif(AppCon001 = Status_SimNao.Sim, true, false)		
		//Obrigatório CPF CNPJ
		&sdtConfiguracoes.isObrCpfCli = false //iif(AppCon002 = Status_SimNao.Sim, true, false)		
		//Permitir Editar Cliente
		&sdtConfiguracoes.IsEditCli = false //iif(AppCon003 = Status_SimNao.Sim, true, false)


		//Iniciar Pedido Como
		&sdtConfiguracoes.PedIsOrc = iif(AppCon004 = 'O', true, false)

		&sdtConfiguracoes.IsConsumidorFinal = iif(AppCon009 > 0, true, false)

		Exit

	when none

		new
			EmpCod = &wwpContext.EmpCod
			AppCod = TipoAplicativo.FORCAVENDAS

			//JDF ESSAS 3 CONFG NAO USA MAIS, O CADASTRO DO CLIENTE É ONLINE.
			//ObrigatorioEndereco
			//RetornaConfSistema.Call(&wwpContext.EmpCod, &wwpContext.FilCod, domConfSistema.TCon006_ObrigatorioEndereco, &Varchar )
			//AppCon001 = iif(&Varchar = 'S', Status_SimNao.Sim, Status_SimNao.Nao)
			//&sdtConfiguracoes.IsObrEndCli = iif(AppCon001 = Status_SimNao.Sim, true, false)
			//Obrigatório CPF CNPJ
			//RetornaConfSistema.Call(&wwpContext.EmpCod, &wwpContext.FilCod, domConfSistema.TCon001_CpfCnpjObrigatorio, &Varchar )
			//AppCon002 = iif(&Varchar = 'S', Status_SimNao.Sim, Status_SimNao.Nao)
			//&sdtConfiguracoes.isObrCpfCli = iif(&Varchar = 'S', true, false)
			//Permitir Editar Cliente
			//AppCon003 = Status_SimNao_PS.Nao
			//&sdtConfiguracoes.IsEditCli = false

			//Iniciar Pedido Como
			AppCon004 = 'O' //PAdrao orcamento
			&sdtConfiguracoes.PedIsOrc = true //Pedido ou Orcamento		
		EndNew

		commit
	EndFor

	For Each Order EmpCod, FilCod
		Where EmpCod = &wwpContext.EmpCod
		Where FilCod = &wwpContext.FilCod

		&sdtConfiguracoes.TabPrmOFF = trim(FilTabPrmCod) 
		&sdtConfiguracoes.TabOFF = trim(FilTabCod) + '.' + trim(Str(FilTabColCod))

		Exit
	EndFor

	IsTemForcaVEndas.Call(&wwpContext, &IsForcaVendas)
	&sdtConfiguracoes.IsForcaVendas = &IsForcaVendas

Endif
